import { useState, useCallback, memo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import type { Village } from '@/types';

// ============================================================
//  VillageMapOverlay
//  SVG overlay placed inside TransformComponent so it zooms
//  and pans in sync with the overview map image.
//
//  Polygon coordinates are stored as fractions (0.0–1.0) of
//  the image dimensions in each village's `mapPolygon` field.
// ============================================================

interface VillageMapOverlayProps {
  villages: Village[];
  selectedVillage: Village | null;
  onVillageClick: (village: Village) => void;
  /** Width & height of the rendered map image (px). Defaults to 100% via viewBox. */
  imageNaturalWidth?: number;
  imageNaturalHeight?: number;
}

interface TooltipState {
  villageId: number;
  x: number; // SVG % coords
  y: number;
}

/** Convert normalised [0,1] polygon points → SVG percentage string */
function toSVGPoints(polygon: [number, number][]): string {
  return polygon.map(([x, y]) => `${(x * 100).toFixed(3)},${(y * 100).toFixed(3)}`).join(' ');
}

/** Compute centroid of a polygon for tooltip placement */
function centroid(polygon: [number, number][]): [number, number] {
  const n = polygon.length;
  const cx = polygon.reduce((s, [x]) => s + x, 0) / n;
  const cy = polygon.reduce((s, [, y]) => s + y, 0) / n;
  return [cx, cy];
}

// Colour palette — each thôn gets a distinct semi-transparent hue
const VILLAGE_COLORS: Record<number, string> = {
  1:  '#06b6d4', // cyan
  2:  '#22c55e', // green
  3:  '#6366f1', // indigo
  4:  '#f59e0b', // amber
  5:  '#ec4899', // pink
  6:  '#f97316', // orange
  7:  '#a3e635', // lime
  8:  '#8b5cf6', // violet
  9:  '#14b8a6', // teal
  10: '#ef4444', // red
  11: '#3b82f6', // blue
  12: '#d97706', // yellow-600
  13: '#7c3aed', // purple
  14: '#0ea5e9', // sky
  15: '#84cc16', // lime-400
  16: '#db2777', // pink-600
};

const VillagePolygon = memo(function VillagePolygon({
  village,
  isSelected,
  isHovered,
  onMouseEnter,
  onMouseLeave,
  onClick,
}: {
  village: Village;
  isSelected: boolean;
  isHovered: boolean;
  onMouseEnter: (v: Village) => void;
  onMouseLeave: () => void;
  onClick: (v: Village) => void;
}) {
  const polygon = village.mapPolygon;
  if (!polygon || polygon.length < 3) return null;

  const color = VILLAGE_COLORS[village.id] ?? '#60a5fa';
  const points = toSVGPoints(polygon);

  const fillOpacity = isSelected ? 0.55 : isHovered ? 0.42 : 0.18;
  const strokeWidth = isSelected ? 0.6 : isHovered ? 0.5 : 0.3;
  const strokeOpacity = isSelected ? 1 : isHovered ? 0.9 : 0.65;

  return (
    <polygon
      points={points}
      fill={color}
      fillOpacity={fillOpacity}
      stroke={isSelected ? '#ffffff' : color}
      strokeWidth={strokeWidth}
      strokeOpacity={strokeOpacity}
      strokeLinejoin="round"
      style={{
        cursor: 'pointer',
        transition: 'fill-opacity 180ms ease, stroke-width 180ms ease',
        filter: isSelected ? `drop-shadow(0 0 3px ${color})` : isHovered ? `drop-shadow(0 0 1.5px ${color})` : 'none',
      }}
      onMouseEnter={() => onMouseEnter(village)}
      onMouseLeave={onMouseLeave}
      onClick={(e) => { e.stopPropagation(); onClick(village); }}
      role="button"
      aria-label={`Chọn ${village.name}`}
      tabIndex={0}
      onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); onClick(village); } }}
    />
  );
});

export const VillageMapOverlay = memo(function VillageMapOverlay({
  villages,
  selectedVillage,
  onVillageClick,
}: VillageMapOverlayProps) {
  const [hoveredId, setHoveredId] = useState<number | null>(null);
  const [tooltip, setTooltip] = useState<TooltipState | null>(null);

  const handleMouseEnter = useCallback((village: Village) => {
    setHoveredId(village.id);
    if (village.mapPolygon && village.mapPolygon.length >= 3) {
      const [cx, cy] = centroid(village.mapPolygon);
      setTooltip({ villageId: village.id, x: cx * 100, y: cy * 100 });
    }
  }, []);

  const handleMouseLeave = useCallback(() => {
    setHoveredId(null);
    setTooltip(null);
  }, []);

  const handleClick = useCallback((village: Village) => {
    onVillageClick(village);
  }, [onVillageClick]);

  // Only render villages that have polygon data
  const villagesToRender = villages.filter(
    (v) => v.mapPolygon && v.mapPolygon.length >= 3
  );

  if (villagesToRender.length === 0) return null;

  const hoveredVillage = tooltip ? villages.find((v) => v.id === tooltip.villageId) : null;

  return (
    // SVG uses a percentage-based viewBox so it scales with the image at any zoom level
    <svg
      viewBox="0 0 100 100"
      preserveAspectRatio="none"
      style={{
        position: 'absolute',
        inset: 0,
        width: '100%',
        height: '100%',
        pointerEvents: 'none', // container ignores events
        zIndex: 10,
        overflow: 'visible',
      }}
      aria-label="Bản đồ thôn xã — có thể nhấp vào từng thôn"
    >
      {/* Polygon layer — pointer-events: all re-enabled on each polygon */}
      <g style={{ pointerEvents: 'all' }}>
        {villagesToRender.map((village) => (
          <VillagePolygon
            key={village.id}
            village={village}
            isSelected={selectedVillage?.id === village.id}
            isHovered={hoveredId === village.id}
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
            onClick={handleClick}
          />
        ))}
      </g>

      {/* Selected village: bright outline ring (rendered last so it's on top) */}
      {selectedVillage?.mapPolygon && selectedVillage.mapPolygon.length >= 3 && (
        <polygon
          points={toSVGPoints(selectedVillage.mapPolygon)}
          fill="none"
          stroke="#ffffff"
          strokeWidth="0.7"
          strokeDasharray="2 1"
          strokeOpacity="0.9"
          style={{ pointerEvents: 'none', filter: `drop-shadow(0 0 2px ${VILLAGE_COLORS[selectedVillage.id] ?? '#60a5fa'})` }}
        />
      )}

      {/* Tooltip label at polygon centroid */}
      {tooltip && hoveredVillage && (
        <g style={{ pointerEvents: 'none' }}>
          {/* Background rect — sized approximately */}
          <rect
            x={tooltip.x - 12}
            y={tooltip.y - 5}
            width={24}
            height={7}
            rx={1.5}
            fill="rgba(0,0,0,0.72)"
            stroke="rgba(255,255,255,0.25)"
            strokeWidth="0.15"
          />
          <text
            x={tooltip.x}
            y={tooltip.y + 0.5}
            textAnchor="middle"
            dominantBaseline="middle"
            fontSize="2.8"
            fontWeight="700"
            fontFamily="Inter, system-ui, sans-serif"
            fill="#ffffff"
            style={{ userSelect: 'none', letterSpacing: '0.02em' }}
          >
            {hoveredVillage.name}
          </text>
        </g>
      )}
    </svg>
  );
});
